const COLORS = ['#00d4aa','#3b82f6','#f59e0b','#f87171','#a78bfa','#34d399','#fb923c','#60a5fa','#f472b6','#4ade80'];
const gridColor = 'rgba(255,255,255,0.05)';
const tickStyle = {color:'#e2e8f0',font:{size:12,weight:'bold'}};
const axisBase  = {ticks:tickStyle, grid:{color:gridColor}};

let activeData = [...RAW_DATA];
let barMode='both', lineMode='line', lowMode='all', topN=5;
let charts={};

/* ── FILTERS ── */
function applyFilters(){
  let search = document.getElementById('searchBox').value.toLowerCase();
  let cat    = document.getElementById('catSelect').value;
  let status = document.getElementById('statusSelect').value;
  activeData = RAW_DATA.filter(p=>{
    if(cat    && p.category !== cat)   return false;
    if(status && p.status  !== status) return false;
    if(search && !p.product.toLowerCase().includes(search) && !p.id.toLowerCase().includes(search)) return false;
    return true;
  });
  let lbl = document.getElementById('filterLabel');
  lbl.textContent = 'Showing '+activeData.length.toLocaleString()+' of 5,000 products';
  lbl.style.color = activeData.length < RAW_DATA.length ? '#00d4aa' : '#94a3b8';
  drawAll(activeData);
}

function resetAll(){
  document.getElementById('searchBox').value='';
  document.getElementById('catSelect').value='';
  document.getElementById('statusSelect').value='';
  document.getElementById('pieHint').textContent='Click a slice to filter by category';
  activeData=[...RAW_DATA];
  let lbl=document.getElementById('filterLabel');
  lbl.textContent='Showing all 5,000 products';
  lbl.style.color='#94a3b8';
  drawAll(activeData);
}

/* ── KPIs ── */
function updateKPIs(data){
  let ts   = data.reduce((a,p)=>a+p.stock,0);
  let low  = data.filter(p=>p.status==='Low'||p.status==='Critical').length;
  let over = data.filter(p=>p.status==='Overstock').length;
  let avgT = data.length ? (data.reduce((a,p)=>a+p.turnover,0)/data.length).toFixed(2) : 0;
  document.getElementById('kTotal').textContent    = ts.toLocaleString();
  document.getElementById('kProducts').textContent = data.length.toLocaleString();
  document.getElementById('kLow').textContent      = low.toLocaleString();
  document.getElementById('kOver').textContent     = over.toLocaleString();
  document.getElementById('kTurn').textContent     = avgT;
}

/* ── DESTROY ── */
function kill(k){if(charts[k]){charts[k].destroy();charts[k]=null;}}

/* ── BAR CHART ── */
function drawBar(data){
  kill('bar');
  let items;
  if(barMode==='top10'){
    items=[...data].sort((a,b)=>b.stock-a.stock).slice(0,10);
  } else if(barMode==='critical'){
    items=data.filter(p=>p.status==='Critical'||p.status==='Low').slice(0,12);
  } else {
    items=data.slice(0,10);
  }
  let datasets=[];
  if(barMode!=='reorder')
    datasets.push({label:'Stock', data:items.map(p=>p.stock), backgroundColor:'rgba(0,212,170,0.85)', borderRadius:4, borderSkipped:false});
  if(barMode==='both'||barMode==='reorder')
    datasets.push({label:'Reorder Level', data:items.map(p=>p.reorder), backgroundColor:'rgba(248,113,113,0.7)', borderRadius:4, borderSkipped:false});

  charts.bar=new Chart(document.getElementById('barChart'),{
    type:'bar',
    data:{labels:items.map(p=>p.product), datasets},
    options:{
      responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:true,labels:{color:'#e2e8f0',font:{size:12,weight:'bold'},boxWidth:12,padding:10}}},
      scales:{
        x:{...axisBase,ticks:{...tickStyle,maxRotation:40,autoSkip:false,font:{size:11,weight:'bold'}}},
        y:axisBase
      }
    }
  });
}

/* ── PIE CHART ── */
function drawPie(data){
  kill('pie');
  let map={};
  data.forEach(p=>{map[p.category]=(map[p.category]||0)+p.stock;});
  let labels=Object.keys(map), vals=Object.values(map);
  charts.pie=new Chart(document.getElementById('pieChart'),{
    type:'doughnut',
    data:{labels,datasets:[{data:vals,backgroundColor:COLORS,borderWidth:2,borderColor:'#1a2e42',hoverOffset:8}]},
    options:{
      responsive:true,maintainAspectRatio:false,cutout:'52%',
      plugins:{
        legend:{display:true,position:'right',labels:{color:'#e2e8f0',font:{size:12,weight:'bold'},boxWidth:12,padding:8}},
        tooltip:{callbacks:{label:ctx=>`${ctx.label}: ${ctx.parsed.toLocaleString()} units`}}
      },
      onClick:(e,els)=>{
        if(!els.length) return;
        let cat=labels[els[0].index];
        document.getElementById('catSelect').value=cat;
        document.getElementById('pieHint').textContent='Filtered: '+cat;
        applyFilters();
      }
    }
  });
}

/* ── LINE / BAR SALES CHART ── */
function drawLine(data){
  kill('line');
  let months=Array(6).fill(0);
  data.forEach(p=>{p.sales.forEach((s,i)=>months[i]+=s);});
  let isArea=lineMode==='area', isBar=lineMode==='bar';
  if(isBar){
    charts.line=new Chart(document.getElementById('lineChart'),{
      type:'bar',
      data:{
        labels:['Jan','Feb','Mar','Apr','May','Jun'],
        datasets:[{label:'Monthly Sales',data:months,backgroundColor:COLORS.slice(0,6),borderRadius:5}]
      },
      options:{
        responsive:true,maintainAspectRatio:false,
        plugins:{legend:{display:false}},
        scales:{x:axisBase,y:axisBase}
      }
    });
  } else {
    charts.line=new Chart(document.getElementById('lineChart'),{
      type:'line',
      data:{
        labels:['Jan','Feb','Mar','Apr','May','Jun'],
        datasets:[{
          label:'Monthly Sales',data:months,
          borderColor:'#00d4aa',
          backgroundColor:isArea?'rgba(0,212,170,0.15)':'transparent',
          fill:isArea,tension:0.4,
          pointBackgroundColor:'#00d4aa',pointRadius:4,borderWidth:2.5
        }]
      },
      options:{
        responsive:true,maintainAspectRatio:false,
        plugins:{legend:{display:false}},
        scales:{x:axisBase,y:axisBase}
      }
    });
  }
}

/* ── LOW STOCK CHART ── */
function drawLow(data){
  kill('low');
  let items;
  if(lowMode==='critical'){
    items=data.filter(p=>p.status==='Critical').slice(0,8);
  } else {
    items=data.filter(p=>p.status==='Critical'||p.status==='Low').slice(0,8);
  }
  if(!items.length) return;
  let colors=items.map(p=>p.status==='Critical'?'rgba(248,113,113,0.9)':'rgba(251,146,60,0.85)');
  charts.low=new Chart(document.getElementById('lowChart'),{
    type:'bar',
    data:{
      labels:items.map(p=>p.product),
      datasets:[{label:'Stock',data:items.map(p=>p.stock),backgroundColor:colors,borderRadius:4}]
    },
    options:{
      indexAxis:'y',responsive:true,maintainAspectRatio:false,
      plugins:{
        legend:{display:false},
        tooltip:{callbacks:{label:ctx=>`Stock: ${ctx.parsed.x} | Status: ${items[ctx.dataIndex].status}`}}
      },
      scales:{x:axisBase,y:{ticks:{...tickStyle,font:{size:11,weight:'bold'}},grid:{display:false}}}
    }
  });
}

/* ── TOP PRODUCTS ── */
function drawTop(data){
  kill('top');
  let sorted=[...data].sort((a,b)=>b.totalSales-a.totalSales).slice(0,topN);
  charts.top=new Chart(document.getElementById('topChart'),{
    type:'bar',
    data:{
      labels:sorted.map(p=>p.product),
      datasets:[{label:'6-Month Sales',data:sorted.map(p=>p.totalSales),backgroundColor:COLORS.slice(0,topN),borderRadius:6}]
    },
    options:{
      responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false}},
      scales:{
        x:{...axisBase,ticks:{...tickStyle,maxRotation:35,font:{size:11,weight:'bold'}}},
        y:axisBase
      }
    }
  });
}

/* ── DRAW ALL ── */
function drawAll(data){
  updateKPIs(data);
  drawBar(data);
  drawPie(data);
  drawLine(data);
  drawLow(data);
  drawTop(data);
}

/* ── TOGGLE HELPERS ── */
function setBar(mode){
  barMode=mode;
  ['btnBoth','btnStock','btnReorder','btnCrit','btnTop10'].forEach(id=>document.getElementById(id).classList.remove('active'));
  let m={both:'btnBoth',stock:'btnStock',reorder:'btnReorder',critical:'btnCrit',top10:'btnTop10'};
  if(m[mode]) document.getElementById(m[mode]).classList.add('active');
  drawBar(activeData);
}
function setLine(mode){
  lineMode=mode;
  document.getElementById('btnLine').classList.toggle('active',mode==='line');
  document.getElementById('btnArea').classList.toggle('active',mode==='area');
  document.getElementById('btnBar2').classList.toggle('active',mode==='bar');
  drawLine(activeData);
}
function setLowMode(mode){
  lowMode=mode;
  document.getElementById('btnLowAll').classList.toggle('active',mode==='all');
  document.getElementById('btnLowCrit').classList.toggle('active',mode==='critical');
  drawLow(activeData);
}
function setTopN(n){
  topN=n;
  document.getElementById('btnT5').classList.toggle('active',n===5);
  document.getElementById('btnT10').classList.toggle('active',n===10);
  drawTop(activeData);
}

/* ── INIT ── */
drawAll(activeData);
